dt-example.js:
new DataTable('#example', {
	columnControl: [
		'order',
		[
			'orderAsc',
			'orderDesc',
			'spacer',
			{
				extend: 'colVis',
				columns: ':not(.always-visible)'
			}
		]
	],
	columnDefs: [
		{
			target: 0,
			className: 'always-visible'
		},
		{
			target: -1,
			visible: false
		}
	],
	ordering: {
		indicators: false,
		handler: false
	}
});
